    terminal, target_subject_id, target_subject_no, target_account_id, target_user_name,
    acting_admin_id, acting_admin_name, reason, token_hash, expire_time, used_time,
    used_ip, status, create_by, create_time, update_by, update_time, remark
) values (
    #{terminal}, #{targetSubjectId}, #{targetSubjectNo}, #{targetAccountId}, #{targetUserName},
    #{actingAdminId}, #{actingAdminName}, #{reason}, #{tokenHash}, #{expireTime}, #{usedTime},
    #{usedIp}, #{status}, #{createBy}, sysdate(), #{updateBy}, #{updateTime}, #{remark}
)

mapper.select:



        and terminal = #{terminal}


        and target_subject_id = #{targetSubjectId}


        and target_subject_no like concat('%', #{targetSubjectNo}, '%')


        and target_account_id = #{targetAccountId}


        and target_user_name like concat('%', #{targetUserName}, '%')


        and acting_admin_name like concat('%', #{actingAdminName}, '%')


        and status = #{status}


        and date_format(create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')


        and date_format(create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')


order by create_time desc, ticket_id desc
